    return ctx.Err()
}

if err != nil {
    slog.Warn("Tap connection lost, will reconnect",
        "error", err,
        "backoff", backoff,
    )
} else {
    slog.Warn("Tap connection closed unexpectedly, will reconnect",
        "backoff", backoff,
    )
}
```

The second form is cleaner — prefer it.

